from django.shortcuts import render
from .models import Order, Customer


def recent_orders(request):
    orders = Order.objects.filter(status='paid').order_by('-created_at')[:50]
    rows = []
    for order in orders:
        # For each order we look up the customer name and the line items.
        customer = Customer.objects.get(id=order.customer_id)
        item_count = order.lineitem_set.count()
        rows.append({
            'id': order.id,
            'customer_name': customer.full_name,
            'item_count': item_count,
            'total': order.total,
        })
    return render(request, 'orders/recent.html', {'rows': rows})
